import { InputControl } from '../InputControl';
import { SelectControl } from '../SelectControl';
import { SmartyAddressInput } from '../SmartyAddressInput/SmartyAddressInput';
import { SmartyAddress } from '../SmartyAddressInput/types';
import { getPostalCodeLabel, getRegionLabel } from './helpers';

interface IProps {
  city?: string;
  country?: string;
  line1?: string;
  line2?: string;
  postalCode?: string;
  region?: string;
  setCity: (value: string) => void;
  setCountry: (value: string) => void;
  setLine1: (value: string) => void;
  setLine2: (value: string) => void;
  setPostalCode: (value: string) => void;
  setRegion: (value: string) => void;
}

export const AddressInputs = ({
  city,
  country,
  line1,
  line2,
  postalCode,
  region,
  setCity,
  setCountry,
  setLine1,
  setLine2,
  setPostalCode,
  setRegion,
}: IProps) => {
  const { t } = useTranslation('formControls');

  const countryRegions = useMemo(() => {
    if (country) {
      return regionOptions[country.toLowerCase()] ?? [];
    } else {
      return [];
    }
  }, [country]);

  const setSmartyAddress = (address: SmartyAddress) => {
    setLine1(address.street_line ?? '');
    setLine2(address.secondary ?? '');
    setCity(address.city ?? '');
    setRegion(address.state ?? '');
    setPostalCode(address.zipcode ?? '');
    setCountry('US');
  };

  return (
    <>
      <div className="flex gap-2">
        <SmartyAddressInput
          name="line1"
          onChange={(e: ChangeEvent<HTMLInputElement>) => setLine1(e.target.value)}
          onSelectAddress={setSmartyAddress}
          value={line1}
        />
        {line1 && (
          <InputControl
            formControlProps={{ className: 'w-full' }}
            label={t('formAddressControl.line2')}
            name="line2"
            onChange={(e: ChangeEvent<HTMLInputElement>) => setLine2(e.target.value)}
            placeholder="Suite 1770"
            value={line2}
          />
        )}
      </div>
      {line1 && (
        <>
          <div className="flex gap-2">
            <InputControl
              label={t('formAddressControl.city')}
              name="city"
              onChange={(e: ChangeEvent<HTMLInputElement>) => setCity(e.target.value)}
              placeholder="New Orleans"
              value={city}
            />
            {!countryRegions.length ? (
              <InputControl
                label={getRegionLabel(country, t)}
                name="region"
                onChange={(e: ChangeEvent<HTMLInputElement>) => setRegion(e.target.value)}
                placeholder="LA"
                value={region}
              />
            ) : (
              <SelectControl
                label={getRegionLabel(country, t)}
                name="region"
                onChange={(e: ChangeEvent<HTMLSelectElement>) => setRegion(e.target.value)}
                options={countryRegions}
                placeholder="LA"
                value={region}
              />
            )}
            <InputControl
              label={getPostalCodeLabel(country, t)}
              name="postalCode"
              onChange={(e) => setPostalCode((e.target as HTMLInputElement).value)}
              placeholder="70112"
              value={postalCode}
            />
          </div>
          <SelectControl
            label={t('formAddressControl.country')}
            name="country"
            onChange={(e: ChangeEvent<HTMLSelectElement>) => setCountry(e.target.value)}
            options={countryOptions}
            placeholder="-"
            value={country}
          />
        </>
      )}
    </>
  );
};

